#[udf]
fn my_median(mut args: Vec<f64>) -> Option<f64> {
    // Filter out NaN values
    args.retain(|x| !x.is_nan());

    if args.is_empty() {
        return None;
    }

    args.sort_by(|a, b| a.partial_cmp(b).unwrap());  // Safe now, no NaNs

    let mid = args.len() / 2;
    if args.len() % 2 == 0 {
        Some((args[mid] + args[mid - 1]) / 2.0)
    } else {
        Some(args[mid])
    }
}

