use arroyo_udf_plugin::udf;
use std::collections::HashMap;

#[udf]
fn my_hashmap(mut values: Vec<f64>, keys: Vec<u64>) -> Option<Vec<u8>> {
    // Create a new hashmap to store the count of each name
    let mut name_counts: HashMap<u64, usize> = HashMap::new();

    // Iterate through the keys and update the count for each name
    for key in keys {
        *name_counts.entry(key).or_insert(0) += 1;
    }

    // Serialize the hashmap to bytes using bincode
    bincode::serialize(&name_counts).ok()
}

